var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"꺄아악!!","JPN":"きゃああっ！？","ENG":"Eeeek!","TWN":"啊啊！！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"이런, 다친 데는 없니?","JPN":"あら、怪我はない？","ENG":"Oh dear, are you alright?","TWN":"哎呀，沒受傷吧？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"정신 단단히 차리렴. 마법을 배우고 마녀가 되는 과정이란 게 그리 안전하지만은 않거든.","JPN":"しっかりしないとダメよ。魔法を学んで魔女になる過程は決して安全ではないわ。","ENG":"You'd better brace yourself. Learning magic and becoming a witch isn't all that safe.","TWN":"妳必須打起精神，學習魔法成為魔女的過程可不輕鬆。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"가, 감사합니다. 침식체를 직접 본 건 처음이라서요.","JPN":"あ、ありがとうございます！　目の前で侵食体を見たのは初めてで……","ENG":"Th-thank you. It's just that I've never seen Corrupted Objects in real life before.","TWN":"謝、謝謝。但因為這是我第一次親眼看到侵蝕體。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"하긴, 누구든 저런 걸 갑자기 마주치면 당황하기 마련이지.","JPN":"確かにあんなものにいきなり出くわしたら、誰だって慌てるでしょうね。","ENG":"I guess anyone would be startled if they ran into one of those things suddenly.","TWN":"也是，換作是誰第一次看到那個東西，都會很慌張。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"뭐야, 순 느림보들뿐이잖아? 더 강한 녀석은 없냐?","JPN":"なによ、全部のろまばかりじゃない！　もっと強いやつはいないの？","ENG":"Why do we only have slowpokes around here? Aren't there any stronger ones?","TWN":"在做什麼，慢死了！沒有更強一點的傢伙嗎？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"가끔은 예외도 있긴 하지만.","JPN":"たまに例外もいるけど。","ENG":"Of course, there are always exceptions.","TWN":"有時也會有例外。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"저어, 그런데 여긴 어디죠?","JPN":"あの、ところでここはどこですか？","ENG":"So... Where are we anyway?","TWN":"請問，這裡是哪裡？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"지하실 문을 열고 들어왔는데 어떻게 이런 넓은 공간이 있는 거예요?","JPN":"地下室の扉の奥に、どうしてこんな広い空間があるんですか？","ENG":"How is there such a large space down here? I thought I was walking into the basement.","TWN":"地下室門後怎麼會有這麼寬敞的空間呢？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"보고도 모르겠어? 여긴 이면세계야.","JPN":"見てわからないか？　ここは裏世界だ。","ENG":"Can't you tell? This is the Counterside.","TWN":"妳還沒看出來嗎？這裡是異界啊。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"침식체가 나타나고 현실이 아닌 공간이 그 외에 뭐가 있겠어.","JPN":"侵食体が現れる現実ではない空間といえば、そこしかないだろ。","ENG":"Why else would there be Corrupted Objects running free like this?","TWN":"出現侵蝕體的非現實空間，除了異界還能是哪裡。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"이면세계는 차원 함선으로만 갈 수 있는 데 아니었어요?","JPN":"裏世界って次元艦船に乗らないと行けない所では？","ENG":"But I thought you needed one of those fancy ships to get to the Counterside.","TWN":"不是只有次元艦船才能去異界嗎？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"수상한 카페 지하실 문이랑 이어져 있다는 얘기는 한 번도 못 들어봤다고요!","JPN":"怪しいカフェの地下室の扉から続いてるなんて話は聞いたことがないです！","ENG":"I never heard of anyone going there through a creepy door in a cafe!","TWN":"我還從沒聽說過異界是和可疑的咖啡店地下室連在一起的！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"지금은 그게 일반적이긴 하지.","JPN":"今はその説が一般的ね。","ENG":"True, that's how it's usually done.","TWN":"現在的確是那樣。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"하지만 생각해 봐. 차원 함선이 없던 시절에도 침식체들은 나타났어.","JPN":"でも考えてみて。次元艦船がなかった時代にも侵食体は現れてたわ。","ENG":"But think about it. We had C.O.s appear even before we had those ships.","TWN":"但妳想想，在沒有次元艦船的時代，也有侵蝕體啊。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그럼 그것들은 어디에서 왔을까?","JPN":"それらはどこから来たと思う？","ENG":"Where do you think they came from?","TWN":"那些侵蝕體是從哪裡來的呢？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그건......","JPN":"えっと……","ENG":"Well...","TWN":"這個……"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"원래 이면세계와의 접점이란 건 어디에나 생길 수 있단다.","JPN":"裏世界との接点なんて、どこにできてもおかしくないの。","ENG":"You see, portals to the Counterside can actually occur anywhere in the world.","TWN":"和異界的連接點是無所不在的。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"버려진 지 오래된 폐가나 침대 밑...... 아니면 옷장 속에도 말이야.","JPN":"長いこと捨てられていた廃屋やベッドの下……クローゼットの中にもね。","ENG":"Inside on old abandoned houses, under the bed, or even in your closet.","TWN":"廢棄的住宅、床底下……或者衣櫃裡。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"여긴 그렇게 자연 발생된 균열 중 하나를 <color=#ffd34c>마법</color>으로 고정시켜 놓은 곳이야.","JPN":"ここはそんな風に自然発生した亀裂の一つを<color=#ffd34c>魔法</color>で固定した場所だ。","ENG":"This is one of those naturally occurring dimensional rifts... but fixed in place with <color=#ffd34c>magic</color>.","TWN":"這裡是將自然形成的裂縫之一用<color=#ffd34c>魔法</color>固定的地方。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"관리국에도 없는 기술이지. 조금은 감탄해도 좋아.","JPN":"管理局も真似できない技術だ。少しは驚いてもいいぞ。","ENG":"Even the Administration can't pull this off. This is the part where you can be legitimately impressed.","TWN":"管理局裡也沒這種技術，妳可以盡情讚嘆。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"대단하긴 한데...... 이렇게 놔두면 위험하지 않나요? 왜 이런 통로를 만든 거예요?","JPN":"すごいと思いますが……このままだと危ないですよね？\\nどうしてこんな通路を作ったんですか？","ENG":"It sure is impressive... but isn't it dangerous to leave something like this open? Why did you make this portal in the first place?","TWN":"是挺了不起的……但這樣不會很危險嗎？為什麼做了這樣一個通道？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"위험하긴. 오히려 그 반대야.","JPN":"危ない？　むしろその逆だ。","ENG":"Dangerous? It's actually the opposite.","TWN":"怎麼會危險，反而這裡很安全。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"이런 식으로 인위적인 통로를 하나 고정시켜 두면, 주변 지역에 다른 균열이 생길 확률은 훨씬 낮아져.","JPN":"こんな風に人為的な通路を固定しておくと\\n周辺地域に別の亀裂が生じる確率がかなり低くなる。","ENG":"If we artificially keep a portal open like this, it significantly lowers the chance of other rifts tearing open in the vicinity.","TWN":"人為固定這樣一個通道後，在周圍地區生成其他裂縫的機率就會降低。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"가스 밸브를 열어서 보일러 전체가 폭발하지 않도록 하는 것과 같은 원리지.","JPN":"ガス栓を開けて、ボイラー全体が爆発しないようにするのと同じ原理だ。","ENG":"It's like how you open the gas valve to keep the entire boiler from exploding.","TWN":"就好像設置煤氣閥門，防止鍋爐爆炸一樣的原理。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"이 도시에 침식재난이 거의 없는 건, 우리가 이 통로를 관리하고 있기 때문이야.","JPN":"この都市に侵食災害があまり起きないのは、ここで通路を管理しているからだ。","ENG":"The reason this city rarely goes through Corruption Disasters is because we keep this portal under our management.","TWN":"這個城市之所以很少有侵蝕災難，就是因為我們管理著這個通道。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"그렇구나...... 듣고 보니 정말 대단하네요!","JPN":"なるほど……本当にすごいですね！","ENG":"I see... Wow, that really is impressive!","TWN":"原來如此……真的很了不起！"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그리고 왜 이런 걸 만들었는지도 간단해. 우리에게 필요한 곳이거든.","JPN":"あと、通路を作った理由も単純だ。ここが妾たちに必要な場所だからな。","ENG":"And the reason why we made this is pretty simple. We need it.","TWN":"至於為什麼會設置這個通道，因為是我們需要。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"필요하다고요? 이면세계인데?","JPN":"必要なんですか？　裏世界なのに？","ENG":"You need it? Why would you need the Counterside?","TWN":"妳們需要？那是異界啊？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"너, 조금 전에 침식체들과 마주쳤을 때 화염구를 만들어 던지지 않았어?","JPN":"新入り、さっき侵食体に出くわした時に火の玉を投げなかったか？","ENG":"Haven't you noticed how you threw a fireball at those C.O.s just now?","TWN":"妳剛才遇到侵蝕體的時候，是不是生成了火焰球丟過去？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"어라? 그러고 보니......?","JPN":"あれ？　そういえば……？","ENG":"Huh? Oh, come to think of it...","TWN":"咦？好像是……？"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"맞아요! 전에는 한 번도 써 본 적 없었는데 자연스럽게 나갔어요!","JPN":"はい！　今まで一度も使ったことはありませんでしたが、自然にできました！","ENG":"You're right! I've never done anything like that before, but it just sort of happened naturally!","TWN":"對欸，之前我從沒有嘗試過，這次很自然地就做出來了。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"아까도 말했지만 그 지팡이는 평범한 워치가 아니야.","JPN":"さっきも言ったが、その杖は平凡なウォッチじゃないんだ。","ENG":"Like I said, that staff is no ordinary Watch.","TWN":"我說過，那根拐杖不是普通的能量環。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그걸 사용하려면 마력이라는 특별한 에너지의 충전이 필요해.","JPN":"それを使うためには、魔力という特別なエネルギーを補充しないといけない。","ENG":"In order to use it, you need to charge a special type of energy called mana.","TWN":"想使用那根拐杖，就必須填充一種叫魔力的特殊能量。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그리고 이 비밀좌표에는 그런 마도구를 구동하기 위한 마력이 가득 차 있지.","JPN":"そしてこの秘密座標は、魔道具の駆動に必要な魔力で満ちている。","ENG":"These secret coordinates are full of the mana required to operate a magical instrument like your staff.","TWN":"在這秘密座標裡，就充滿了驅動魔導具的魔力。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그래서 네가 처음으로 지팡이의 힘을 사용할 수 있게 된 거야.","JPN":"だから初めて杖の力を使えるようになったのだ。","ENG":"That's why you could use the power of the staff for the first time.","TWN":"所以妳第一次使用了那拐杖的力量。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"물론 제대로 사용하려면 마법 이론에 대한 공부가 더 필요하겠지만.","JPN":"もちろん、きちんと使うためには魔法理論に関する勉強がもっと必要だがな。","ENG":"Of course, you'll need to brush up on your magic theory to learn how to use the staff properly.","TWN":"當然，如果妳想充分利用，還需要多學習魔法理論。"},"stage":{"bg":"COUNTERSIDE_WITCH","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};